static const float DCT_NORMS[13] = {
  0.196116f, 0.277350f, 0.277350f, 0.277350f, 0.277350f, 0.277350f, 0.277350f, 0.277350f, 0.277350f, 0.277350f, 0.277350f, 0.277350f, 0.277350f
};


// Compute 13 MFCC coefficients from arduinoFFT magnitudes.
//
// IMPORTANT: call BEFORE FFT.complexToMagnitude if you need to reuse vReal,
// OR pass the magnitude array after complexToMagnitude.
//
// magnitudes : double array, size >= 256 (arduinoFFT complexToMagnitude output)
//              Only bins [0..254] are used — bin 255 (Nyquist) is intentionally
//              skipped to match Python's stft[:n_fft//2 - 1] slicing.
// out_mfcc   : float[13] output array
//
static void computeLibMFCC(double* magnitudes, float* out_mfcc) {
    float fe[26];
    for (int l = 0; l < 26; l++) {
        float energy = 0.0f;
        for (int k = 0; k < 255; k++) {
            energy += FILTERBANK[l][k] * (float)magnitudes[k];
        }
        fe[l] = (energy > 0.0f) ? logf(energy) : 0.0f;
    }
    for (int m = 0; m < 13; m++) {
        float s = 0.0f;
        for (int l = 0; l < 26; l++) s += DCT_COSINES[m][l] * fe[l];
        out_mfcc[m] = DCT_NORMS[m] * s;
    }
}

